import * as fs from 'node:fs';
import { readFile } from 'node:fs/promises';

import { Args, Command } from '@thymian/cli-common/oclif';
import { parse } from 'csv-parse';

export default class Analyze extends Command {
  static override args = {
    file: Args.file({
      required: true,
      exists: true,
      description: 'The CSV file to analyze.',
    }),
  };

  static override description =
    'Analyzes CSV files generated by the evaluation command.';

  static override examples = [
    '<%= config.bin %> <%= command.id %> ./results/run-1.csv',
  ];

  override async run(): Promise<void> {
    const { args } = await this.parse(Analyze);

    const parser = parse({
      delimiter: ',',
      columns: true,
      trim: true,
    });

    const rules: Record<string, number> = {};
    const versions: Record<string, number> = {};
    const totalViolations: Record<'errors' | 'warnings' | 'hints', number> = {
      errors: 0,
      warnings: 0,
      hints: 0,
    };
    let totalCount = 0;
    let successCount = 0;
    const reasons: Record<string, number> = {};
    let totalCountOfViolations = 0;
    const filesWithoutViolations: string[] = [];
    const filesWithoutErrors: string[] = [];
    const filesWithoutErrorsAndWarnings: string[] = [];
    const sizes: Record<string, number> = {};
    const paths: string[] = [];

    const standardColumns = [
      'title',
      'path',
      'version',
      'success',
      'reason',
      'number of violations',
      'errors',
      'warnings',
      'hints',
    ];

    parser.on('readable', () => {
      let record;
      while ((record = parser.read()) !== null) {
        const version = record.version?.trim() || 'unknown';
        const success = record.success?.toLowerCase() === 'true';
        const reason = record.reason?.trim() || 'null';
        const violations = parseInt(record['number of violations'] || '0', 10);
        const errors = parseInt(record.errors || '0', 10);
        const warnings = parseInt(record.warnings || '0', 10);
        const hints = parseInt(record.hints || '0', 10);
        const path = record.path?.trim();

        if (success && reason === 'null') {
          if (!path) {
            throw new Error(
              'Path is required for successful analysis.' + record.title,
            );
          }
          const stats = fs.statSync(path);
          sizes[path] = stats.size;
          paths.push(path);
        }

        // Track version distribution
        versions[version] = (versions[version] || 0) + 1;

        // Track violations
        totalViolations.errors += errors;
        totalViolations.warnings += warnings;
        totalViolations.hints += hints;
        totalCountOfViolations += violations;

        totalCount++;

        if (success) {
          successCount++;
        }

        // Track reasons
        reasons[reason] = (reasons[reason] || 0) + 1;

        if (violations === 0 && success) {
          filesWithoutViolations.push(record.path);
        }

        if (errors === 0 && success) {
          filesWithoutErrors.push(record.path);

          if (warnings === 0) {
            filesWithoutErrorsAndWarnings.push(record.path);
          }
        }

        // Extract rule violations from remaining columns
        for (const [key, value] of Object.entries(record)) {
          if (!standardColumns.includes(key) && value) {
            const violationCount = parseInt(value as string, 10);
            rules[key] = (rules[key] || 0) + violationCount;
          }
        }
      }
    });

    let skippedRecords = 0;

    parser.on('skip', () => {
      skippedRecords++;
    });

    parser.on('error', (error) => {
      this.error(`CSV parsing error: ${error.message}`, { exit: 1 });
    });

    const csvContent = await readFile(args.file, 'utf8');
    parser.write(csvContent);
    parser.end();

    // Wait for parsing to complete
    await new Promise((resolve) => parser.on('end', resolve));

    // Display results
    this.log('\n=== Analysis Results ===\n');

    if (skippedRecords > 0) {
      this.log(`⚠️  Skipped ${skippedRecords} malformed records\n`);
    }

    this.log(`Total APIs analyzed: ${totalCount}`);
    this.log(
      `Successful: ${successCount} (${((successCount / totalCount) * 100).toFixed(1)}%)`,
    );
    this.log(
      `Failed: ${totalCount - successCount} (${(((totalCount - successCount) / totalCount) * 100).toFixed(1)}%)\n`,
    );

    this.log('--- Violations Summary ---');
    this.log(`Total violations: ${totalCountOfViolations}`);
    this.log(`Errors: ${totalViolations.errors}`);
    this.log(`Warnings: ${totalViolations.warnings}`);
    this.log(`Hints: ${totalViolations.hints}\n`);

    this.log('--- OpenAPI Versions ---');
    const sortedVersions = Object.entries(versions).sort((a, b) => b[1] - a[1]);
    for (const [version, count] of sortedVersions) {
      this.log(
        `${version}: ${count} (${((count / totalCount) * 100).toFixed(1)}%)`,
      );
    }

    this.log('\n--- OpenAPI Versions (Success only) ---');
    delete versions['unknown'];
    delete versions['null'];
    const sortedSuccessfulVersions = Object.entries(versions).sort(
      (a, b) => b[1] - a[1],
    );
    for (const [version, count] of sortedSuccessfulVersions) {
      this.log(
        `${version}: ${count} (${((count / successCount) * 100).toFixed(1)}%)`,
      );
    }

    this.log('\n--- Failure Reasons ---');
    const sortedReasons = Object.entries(reasons).sort((a, b) => b[1] - a[1]);
    for (const [reason, count] of sortedReasons) {
      if (reason !== 'null') {
        this.log(`${reason}: ${count}`);
      }
    }

    this.log('\n--- Rules ---');
    const sortedRules = Object.entries(rules).sort((a, b) => b[1] - a[1]);
    for (const [rule, count] of sortedRules) {
      this.log(`${rule}: ${count}`);
    }

    this.log('\n--- Number of Documents without any Violation ---');
    this.log(`${filesWithoutViolations.length}`);

    this.log('\n--- Number of Documents without any Error ---');
    this.log(`${filesWithoutErrors.length}`);

    this.log('\n--- Number of Documents without any Error or Warning ---');
    this.log(filesWithoutErrorsAndWarnings.length.toString());

    this.log('\n--- Rules that got not violated in any of the documents ---');
    for (const [name, count] of Object.entries(rules)) {
      if (count === 0) {
        this.log(name);
      }
    }
  }
}
